(function () {

	var config = {
		buttonId: '#feedback-form-widget',

		modalClass: 'modal-feedback-form',
		buttonClass: 'modal-feedback-control'
	};

	config.offsetTarget = $(config.buttonId).data('offset-target');

	var Button = function () {
		function Button(config, modal) {
			_classCallCheck(this, Button);

			this.url = config.url;
			this.offsetTarget = document.querySelector(config.offsetTarget);
			this.createButton(config.buttonClass);
			this.attachScrollHandler(this.offsetTarget);
			this.attachClickHandler();
			this.modal = modal;
		}

		_createClass(Button, [{
			key: 'createButton',
			value: function createButton(buttonClass) {
				this.button = document.querySelector('.' + buttonClass);
			}
		}, {
			key: 'show',
			value: function show() {
				$(this.button).fadeIn();
			}
		}, {
			key: 'hide',
			value: function hide() {
				$(this.button).fadeOut();
			}
		}, {
			key: 'attachScrollHandler',
			value: function attachScrollHandler(offsetTarget) {
				if (offsetTarget === null) {
					return false;
				}

				var _this = this;
				window.onscroll = function () {
					window.scrollY = window.scrollY || window.document.body.scrollTop;
					var rect = offsetTarget.getBoundingClientRect();
					var targetPos = {
						top: rect.height + (rect.top + window.scrollY)
					};

					if (window.scrollY > targetPos.top) {
						_this.show();
					} else {
						_this.hide();
					}

					targetPos.top = targetPos.top - window.scrollY;
					if (targetPos.top > 0) {
						_this.button.style.top = targetPos.top + 'px';
					} else {
						_this.button.style.top = 0;
					}
				};
			}
		}, {
			key: 'attachClickHandler',
			value: function attachClickHandler() {
				var self = this;
				var button = this.button;
				button.addEventListener('click', function (e) {
					e.preventDefault();

					if (self.modal.isLoaded()) {
						self.modal.show();
						return;
					}

					var url = button.getAttribute('data-url');
					self.modal.loadData(url).show();
				});
			}
		}]);

		return Button;
	}();

	var Modal = function () {
		function Modal(modalClass) {
			_classCallCheck(this, Modal);

			this.modal = new tingle.modal({
				closeMethods: ['overlay', 'button', 'escape'],
				cssClass: [modalClass],
				closeLabel: 'Закрыть'
			});
			this.loaded = false;
		}

		_createClass(Modal, [{
			key: 'setLoaded',
			value: function setLoaded(state) {
				this.loaded = state;
				return this;
			}
		}, {
			key: 'isLoaded',
			value: function isLoaded() {
				return this.loaded;
			}
		}, {
			key: 'show',
			value: function show() {
				this.modal.open();
				return this;
			}
		}, {
			key: 'hide',
			value: function hide() {
				this.modal.close();
				return this;
			}
		}, {
			key: 'loadData',
			value: function loadData(url) {
				if (url) {
					this.setBody(url);
					this.setLoaded(true);
				}
				return this;
			}
		}, {
			key: 'setBody',
			value: function setBody(url) {
				var iframe = document.createElement('iframe');
				iframe.className = 'frame-feedback';
				iframe.setAttribute('src', url);
				var wrapper = document.createElement('div');
				wrapper.className = 'frame-wrapper';
				wrapper.appendChild(iframe);

				this.modal.setContent(wrapper);

				wrapper = this.modal.getContent().querySelector('.frame-wrapper');
				wrapper.classList.add('ajax-loading');
				iframe = wrapper.querySelector('iframe');
				iframe.onload = function () {
					wrapper.classList.remove('ajax-loading');
				};

				return this;
			}
		}, {
			key: 'getBody',
			value: function getBody() {
				return this.modal.modalBoxContent;
			}
		}]);

		return Modal;
	}();

	new Button(config, new Modal(config.modalClass));
})();
